div.script:
document.addEventListener("mousemove", e => {
    const x = (e.clientX / window.innerWidth - 0.5) * 20;
    const y = (e.clientY / window.innerHeight - 0.5) * -20;
    scene.style.transform = `rotateY(${x}deg) rotateX(${y}deg)`;
});

/* MODAL */
const modalBG = document.getElementById("forms-modal-bg");
const modal = document.getElementById("forms-modal");
const modalTitle = document.getElementById("forms-modal-title");
const modalDesc = document.getElementById("forms-modal-desc");
const modalButton = document.getElementById("forms-modal-button");

document.querySelectorAll(".icon").forEach(icon => {
    icon.addEventListener("click", () => {
        modalTitle.textContent = icon.dataset.title;
        modalDesc.textContent = icon.dataset.desc;
        modalButton.href = icon.dataset.link;

        modalBG.style.display = "flex";
        setTimeout(() => modal.style.transform = "scale(1)", 10);
        setTimeout(() => modal.style.opacity = "1", 10);
    });
});

modalBG.addEventListener("click", e => {
    if (e.target === modalBG) {
        modal.style.transform = "scale(0.6)";
        modal.style.opacity = "0";
        setTimeout(() => modalBG.style.display = "none", 200);
    }
});

function tabCloak() {
  const win = window.open("about:blank", "_blank");
  win.document.open();
  win.document.write(document.documentElement.outerHTML);
  win.document.close();
}

function downloadOS() {
  const code = document.documentElement.outerHTML;
  const blob = new Blob([code], { type: "text/html" });
  const url = URL.createObjectURL(blob);

  const a = document.createElement("a");
  a.href = url;
  a.download = "UnknownsOS.html";
  a.click();

  URL.revokeObjectURL(url);
}

body.script:
  // --- Loading particles ---
  const particlesContainer = document.getElementById("loading-particles");
  for (let i = 0; i < 24; i++) {
    const p = document.createElement("div");
    p.className = "particle";
    p.style.left = Math.random() * 100 + "%";
    p.style.animationDelay = (Math.random() * 4) + "s";
    p.style.animationDuration = (3 + Math.random() * 3) + "s";
    particlesContainer.appendChild(p);
  }

  // --- Loading text sequence ---
  const loadingSub = document.getElementById("loading-subtext");
  const loadingLog = document.getElementById("loading-log");
  const loadingSteps = [
    "Initializing Unknowns Engine...",
    "Charging Neon Core...",
    "Syncing UI Modules...",
    "Preparing Environment...",
    "Starting Unknowns OS..."
  ];
  const logSteps = [
    "Boot sequence started...",
    "Core voltage stable.",
    "UI modules verified.",
    "Environment variables loaded.",
    "Handing off to Unknowns OS..."
  ];
  let stepIndex = 0;
  const stepInterval = setInterval(() => {
    if (stepIndex < loadingSteps.length) {
      loadingSub.textContent = loadingSteps[stepIndex];
      loadingLog.textContent = logSteps[stepIndex];
      stepIndex++;
    } else {
      clearInterval(stepInterval);
    }
  }, 900);

  // --- Finish loading after 5s with smooth transition ---
  const loadingScreen = document.getElementById("loading-screen");
  const desktop = document.getElementById("desktop");

  setTimeout(() => {
    loadingScreen.classList.add("fade-out");
    setTimeout(() => {
      loadingScreen.style.display = "none";
      desktop.style.display = "flex";
      requestAnimationFrame(() => {
        desktop.classList.add("visible");
      });
    }, 400);
  }, 5000);

  // --- Time & date (12-hour) ---
  function formatTime12(date) {
    let h = date.getHours();
    const m = date.getMinutes().toString().padStart(2, "0");
    const ampm = h >= 12 ? "PM" : "AM";
    h = h % 12;
    if (h === 0) h = 12;
    return `${h}:${m} ${ampm}`;
  }

  function updateTime() {
    const now = new Date();
    const timeStr = formatTime12(now);
    const dateStr = now.toLocaleDateString(undefined, {
      weekday: "long",
      month: "long",
      day: "numeric",
      year: "numeric"
    });
    document.getElementById("center-time").textContent = timeStr;
    document.getElementById("center-date").textContent = dateStr;
    document.getElementById("taskbar-time").textContent = timeStr;
  }
  updateTime();
  setInterval(updateTime, 1000);

  // --- Fake weather ---
  const weatherOptions = [
    { main: "Sunny", temp: "86°F", extra: "Clear skies" },
    { main: "Partly Cloudy", temp: "79°F", extra: "Light breeze" },
    { main: "Cloudy", temp: "73°F", extra: "Calm" },
    { main: "Stormy", temp: "70°F", extra: "Thunder nearby" }
  ];
  const w = weatherOptions[Math.floor(Math.random() * weatherOptions.length)];
  document.getElementById("weather-main").textContent = w.main;
  document.getElementById("weather-temp").textContent = w.temp;
  document.getElementById("weather-extra").textContent = "Palm Springs • " + w.extra;

  // --- Fake battery ---
  const batteryPercent = Math.floor(40 + Math.random() * 60);
  document.getElementById("battery-percent").textContent = batteryPercent + "%";
  document.getElementById("battery-level").style.width = batteryPercent + "%";

  // --- View Counter (Saved) ---
  (function handleViewCounter() {
    let views = localStorage.getItem("uo_view_count");
    if (!views) {
      views = 1;
    } else {
      views = parseInt(views) + 1;
    }
    localStorage.setItem("uo_view_count", views);
    document.getElementById("center-views").textContent = "Views: " + views;
  })();

  // --- Taskbar app opening / window management ---
  const appButtons = document.querySelectorAll(".taskbar-app");
  const windows = document.querySelectorAll(".window");

  function bringToFront(win) {
    let maxZ = 10;
    windows.forEach(w => {
      const z = parseInt(window.getComputedStyle(w).zIndex) || 10;
      if (z > maxZ) maxZ = z;
    });
    win.style.zIndex = maxZ + 1;
  }

  function openApp(appName) {
    windows.forEach(win => {
      if (win.dataset.app === appName) {
        win.classList.remove("hidden");
        bringToFront(win);
      }
    });
    appButtons.forEach(btn => {
      btn.classList.toggle("active", btn.dataset.open === appName);
    });
  }

  appButtons.forEach(btn => {
    btn.addEventListener("click", () => {
      const app = btn.dataset.open;
      const win = document.querySelector(`.window[data-app="${app}"]`);
      if (win.classList.contains("hidden")) {
        openApp(app);
      } else {
        bringToFront(win);
      }
    });
  });

  // --- Window controls (true fullscreen, default positions) ---
  windows.forEach(win => {
    const controls = win.querySelectorAll(".window-btn");
    let savedBounds = null;
    let isFullscreen = false;

    controls.forEach(btn => {
      btn.addEventListener("click", () => {
        const action = btn.dataset.action;
        if (action === "close") {
          win.classList.add("hidden");
          const appName = win.dataset.app;
          appButtons.forEach(b => {
            if (b.dataset.open === appName) b.classList.remove("active");
          });
        } else if (action === "minimize") {
          win.classList.add("hidden");
        } else if (action === "maximize") {
          if (!isFullscreen) {
            savedBounds = {
              top: win.style.top,
              left: win.style.left,
              width: win.style.width,
              height: win.style.height,
              position: win.style.position,
              borderRadius: win.style.borderRadius,
              boxShadow: win.style.boxShadow
            };
            win.style.position = "fixed";
            win.style.top = "0";
            win.style.left = "0";
            win.style.width = "100%";
            win.style.height = "100%";
            win.style.borderRadius = "0";
            win.style.boxShadow = "none";
            isFullscreen = true;
          } else {
            if (savedBounds) {
              win.style.position = savedBounds.position || "absolute";
              win.style.top = savedBounds.top || "12%";
              win.style.left = savedBounds.left || "10%";
              win.style.width = savedBounds.width || "min(720px, 92vw)";
              win.style.height = savedBounds.height || "min(440px, 72vh)";
              win.style.borderRadius = savedBounds.borderRadius || "12px";
              win.style.boxShadow = savedBounds.boxShadow || "0 0 26px rgba(0, 255, 106, 0.35)";
            }
            isFullscreen = false;
          }
          bringToFront(win);
        }
      });
    });

    win.addEventListener("mousedown", () => bringToFront(win));
  });

  // --- Settings: wallpaper (with saving) ---
  const wallpaperUrlInput = document.getElementById("wallpaper-url");
  const applyWallpaperBtn = document.getElementById("apply-wallpaper");
  const presetButtons = document.querySelectorAll('[data-wallpaper]');

  const WALLPAPER_TYPE_KEY = "uo_wallpaper_type";
  const WALLPAPER_URL_KEY = "uo_wallpaper_url";

  function setWallpaper(typeOrUrl, isPreset = true, save = true) {
    if (isPreset) {
      if (typeOrUrl === "default") {
        desktop.style.backgroundImage = "";
        desktop.style.backgroundSize = "";
        desktop.style.backgroundPosition = "";
      } else if (typeOrUrl === "grid") {
        desktop.style.backgroundImage =
          "radial-gradient(circle at top, #0a1f14 0, #020403 45%, #000 100%), " +
          "linear-gradient(#0b2a18 1px, transparent 1px), " +
          "linear-gradient(90deg, #0b2a18 1px, transparent 1px)";
        desktop.style.backgroundSize = "cover, 40px 40px, 40px 40px";
        desktop.style.backgroundPosition = "center";
      } else if (typeOrUrl === "dark") {
        desktop.style.backgroundImage =
          "radial-gradient(circle at 20% 0%, #0b2a18 0, #020403 40%, #000 100%)";
        desktop.style.backgroundSize = "cover";
        desktop.style.backgroundPosition = "center";
      }
      if (save) {
        localStorage.setItem(WALLPAPER_TYPE_KEY, typeOrUrl);
        localStorage.removeItem(WALLPAPER_URL_KEY);
      }
    } else {
      desktop.style.backgroundImage = `url("${typeOrUrl}")`;
      desktop.style.backgroundSize = "cover";
      desktop.style.backgroundPosition = "center";
      if (save) {
        localStorage.setItem(WALLPAPER_TYPE_KEY, "custom");
        localStorage.setItem(WALLPAPER_URL_KEY, typeOrUrl);
      }
    }
  }

  applyWallpaperBtn.addEventListener("click", () => {
    const url = wallpaperUrlInput.value.trim();
    if (url) setWallpaper(url, false, true);
  });

  presetButtons.forEach(btn => {
    btn.addEventListener("click", () => {
      setWallpaper(btn.dataset.wallpaper, true, true);
    });
  });

  (function loadSavedWallpaper() {
    const type = localStorage.getItem(WALLPAPER_TYPE_KEY);
    const url = localStorage.getItem(WALLPAPER_URL_KEY);
    if (type === "custom" && url) {
      wallpaperUrlInput.value = url;
      setWallpaper(url, false, false);
    } else if (type) {
      setWallpaper(type, true, false);
    }
  })();

  // --- Calculator (with saved mode) ---
  const calcDisplay = document.getElementById("calc-display");
  const calcKeypad = document.getElementById("calc-keypad");
  const modeButtons = document.querySelectorAll(".calc-mode-btn");

  const CALC_MODE_KEY = "uo_calc_mode";

  let calcMode = "basic";
  let calcExpression = "";

  const basicKeys = [
    "C", "←", "%", "/",
    "7", "8", "9", "*",
    "4", "5", "6", "-",
    "1", "2", "3", "+",
    "0", ".", "="
  ];

  const sciKeys = [
    "C", "←", "(", ")",
    "sin", "cos", "tan", "/",
    "7", "8", "9", "*",
    "4", "5", "6", "-",
    "1", "2", "3", "+",
    "0", ".", "^", "="
  ];

  function renderKeys() {
    calcKeypad.innerHTML = "";
    const keys = calcMode === "basic" ? basicKeys : sciKeys;
    keys.forEach(k => {
      const btn = document.createElement("button");
      btn.className = "calc-btn";
      if (["/", "*", "-", "+", "%", "^"].includes(k)) btn.classList.add("op");
      if (k === "=") btn.classList.add("equal");
      if (["sin", "cos", "tan"].includes(k)) btn.classList.add("small");
      btn.textContent = k;
      btn.addEventListener("click", () => handleCalcKey(k));
      calcKeypad.appendChild(btn);
    });
  }

  function updateDisplay() {
    calcDisplay.textContent = calcExpression || "0";
  }

  function handleCalcKey(key) {
    if (key === "C") {
      calcExpression = "";
    } else if (key === "←") {
      calcExpression = calcExpression.slice(0, -1);
    } else if (key === "=") {
      try {
        let expr = calcExpression;
        if (calcMode === "scientific") {
          expr = expr
            .replace(/sin\(/g, "Math.sin(")
            .replace(/cos\(/g, "Math.cos(")
            .replace(/tan\(/g, "Math.tan(")
            .replace(/\^/g, "**");
        }
        const result = Function("return " + expr)();
        calcExpression = (result !== undefined && !isNaN(result)) ? String(result) : "";
      } catch {
        calcExpression = "Error";
      }
    } else {
      if (calcExpression === "Error") calcExpression = "";
      if (["sin", "cos", "tan"].includes(key)) {
        calcExpression += key + "(";
      } else {
        calcExpression += key;
      }
    }
    updateDisplay();
  }

  modeButtons.forEach(btn => {
    btn.addEventListener("click", () => {
      const mode = btn.dataset.mode;
      if (mode !== calcMode) {
        calcMode = mode;
        localStorage.setItem(CALC_MODE_KEY, calcMode);
        modeButtons.forEach(b => b.classList.toggle("active", b.dataset.mode === mode));
        calcExpression = "";
        updateDisplay();
        renderKeys();
      }
    });
  });

  (function loadCalcMode() {
    const saved = localStorage.getItem(CALC_MODE_KEY);
    if (saved === "scientific" || saved === "basic") {
      calcMode = saved;
    }
    modeButtons.forEach(b => b.classList.toggle("active", b.dataset.mode === calcMode));
    renderKeys();
    updateDisplay();
  })();

  /* ============================================================
   DRAGGABLE + RESIZABLE WINDOWS FOR UNKNOWNs OS
   ============================================================ */
windows.forEach(win => {
  const header = win.querySelector(".window-header");
  let isDragging = false;
  let offsetX = 0;
  let offsetY = 0;

  // --- DRAGGING ---
  header.addEventListener("mousedown", e => {
    if (win.classList.contains("fullscreen")) return;
    isDragging = true;
    win.style.transition = "none";
    offsetX = e.clientX - win.offsetLeft;
    offsetY = e.clientY - win.offsetTop;
    win.style.opacity = "0.92";
    win.style.boxShadow = "0 0 30px #00ff6a";
  });

  document.addEventListener("mousemove", e => {
    if (!isDragging) return;
    win.style.left = (e.clientX - offsetX) + "px";
    win.style.top = (e.clientY - offsetY) + "px";
  });

  document.addEventListener("mouseup", () => {
    if (isDragging) {
      win.style.opacity = "1";
      win.style.boxShadow = "0 0 26px rgba(0,255,106,0.35)";
    }
    isDragging = false;
  });

  // --- RESIZING ---
  win.style.resize = "both";
  win.style.overflow = "hidden";
  win.style.minWidth = "260px";
  win.style.minHeight = "160px";
});


/* ============================================================
   ANNOUNCEMENT BAR (with saved close state)
   ============================================================ */
const announcementBar = document.getElementById("announcement-bar");
const announcementClose = document.getElementById("announcement-close");
const ANNOUNCEMENT_KEY = "uo_announcement_closed_v1";

// Show announcement only if not closed before
if (!localStorage.getItem(ANNOUNCEMENT_KEY)) {
  announcementBar.style.display = "block";
}

announcementClose.addEventListener("click", () => {
  announcementBar.style.display = "none";
  localStorage.setItem(ANNOUNCEMENT_KEY, "true");
});


/* ============================================================
   REAL WEATHER + TEMPERATURE + LOCATION
   ============================================================ */

function updateRealWeather() {
  if (!navigator.geolocation) {
    console.warn("Geolocation not supported.");
    return;
  }

  navigator.geolocation.getCurrentPosition(async pos => {
    const lat = pos.coords.latitude;
    const lon = pos.coords.longitude;

    try {
      // Fetch weather
      const url = `https://api.open-meteo.com/v1/forecast?latitude=${lat}&longitude=${lon}&current_weather=true`;
      const res = await fetch(url);
      const data = await res.json();

      const weather = data.current_weather;

      // Convert weather code → readable text
      const weatherNames = {
        0: "Clear",
        1: "Mainly Clear",
        2: "Partly Cloudy",
        3: "Cloudy",
        45: "Fog",
        48: "Fog",
        51: "Light Drizzle",
        61: "Rain",
        71: "Snow",
        80: "Rain Showers",
        95: "Thunderstorm"
      };

      const desc = weatherNames[weather.weathercode] || "Weather";

      // Update UI
      document.getElementById("weather-main").textContent = desc;
      document.getElementById("weather-temp").textContent = weather.temperature + "°F";

      // Reverse‑geocode city name
      const geoRes = await fetch(
        `https://nominatim.openstreetmap.org/reverse?lat=${lat}&lon=${lon}&format=json`
      );
      const geoData = await geoRes.json();

      const city = geoData.address.city ||
                   geoData.address.town ||
                   geoData.address.village ||
                   geoData.address.county ||
                   "Your Area";

      document.getElementById("weather-extra").textContent =
        `${city} • ${desc}`;

    } catch (err) {
      console.error("Weather fetch failed:", err);
    }
  }, err => {
    console.warn("User denied location.");
  });
}

updateRealWeather();

          console.log("Unknowns OS SVG loaded");
